  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import useUniverseCamera from './hooks/useUniverseCamera';
  7→import DeepSpaceLayer from './layers/DeepSpaceLayer';
  8→import MidGalaxyLayer from './layers/MidGalaxyLayer';
  9→import InteractiveLayer from './layers/InteractiveLayer';
 10→import { extractSnippet, userHomeCoords } from './utils/starUtils';
 11→import styles from './Universe.module.css';
 12→
 13→const Universe = () => {
 14→    const navigate = useNavigate();
 15→    const { user } = useAuth();
 16→    const userId = user?.userData?.[0]?.id || null;
 17→
 18→    const debounceRef = useRef(null);
 19→    const [posts, setPosts] = useState(new Map());
 20→    const [selectedPost, setSelectedPost] = useState(null);
 21→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 22→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 23→    const [pulsingId, setPulsingId] = useState(null);
 24→    // null = still loading, true/false = resolved
 25→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 26→
 27→    const {
 28→        stageRef,
 29→        stageSize,
 30→        camera,
 31→        zoom,
 32→        isDragging,
 33→        centerWorld,
 34→        getLayerProps,
 35→        getViewportBounds,
 36→        stageEvents,
 37→        flyTo,
 38→    } = useUniverseCamera(userId, hasOwnPosts);
 39→
 40→    // Debounced fetch on camera/zoom change
 41→    useEffect(() => {
 42→        if (debounceRef.current) clearTimeout(debounceRef.current);
 43→
 44→        debounceRef.current = setTimeout(async () => {
 45→            const bounds = getViewportBounds();
 46→            try {
 47→                const result = await getUniversePosts(bounds.minX, bounds.maxX, bounds.minY, bounds.maxY, 200);
 48→                if (result?.data) {
 49→                    setPosts(prev => {
 50→                        const next = new Map(prev);
 51→                        for (const post of result.data) {
 52→                            next.set(post.id, post);
 53→                        }
 54→                        return next;
 55→                    });
 56→                    // Check if any returned posts belong to this user
 57→                    if (userId && hasOwnPosts === null) {
 58→                        const ownsAny = result.data.some(p => p.users?.id === userId);
 59→                        setHasOwnPosts(ownsAny);
 60→                    }
 61→                }
 62→            } catch (err) {
 63→                console.error('Failed to fetch universe posts:', err);
 64→            }
 65→        }, 400);
 66→
 67→        return () => {
 68→            if (debounceRef.current) clearTimeout(debounceRef.current);
 69→        };
 70→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 71→
 72→    const handleStarClick = useCallback((post) => {
 73→        setSelectedPost(post);
 74→        setSelectedGalaxy(null);
 75→        setGalaxyProfile(null);
 76→        setPulsingId(post.id);
 77→        setTimeout(() => setPulsingId(null), 400);
 78→    }, []);
 79→
 80→    const handleGalaxyClick = useCallback(async (galaxy) => {
 81→        setSelectedGalaxy(galaxy);
 82→        setSelectedPost(null);
 83→        setGalaxyProfile(null);
 84→
 85→        // Zoom into the galaxy
 86→        flyTo(galaxy.x, galaxy.y, 0.8);
 87→
 88→        try {
 89→            const data = await getUserData(galaxy.userId);
 90→            const profile = data?.userData?.[0] || null;
 91→            setGalaxyProfile(profile);
 92→        } catch (err) {
 93→            console.error('Failed to fetch galaxy profile:', err);
 94→        }
 95→    }, [flyTo]);
 96→
 97→    const handleReadPost = useCallback(() => {
 98→        if (!selectedPost) return;
 99→        navigate(`/home/post/${selectedPost.id}`);
100→    }, [selectedPost, navigate]);
101→
102→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
103→    const showTitles = zoom > 0.5;
104→
105→    // Derive one label per unique user (galaxy)
106→    const galaxies = useMemo(() => {
107→        const seen = new Map();
108→        for (const post of postArray) {
109→            const uid = post.users?.id;
110→            if (!uid || seen.has(uid)) continue;
111→            const home = userHomeCoords(uid);
112→            seen.set(uid, {
113→                userId: uid,
114→                name: post.users?.name || 'Anonymous',
115→                x: home.x,
116→                y: home.y,
117→            });
118→        }
119→        return Array.from(seen.values());
120→    }, [postArray]);
121→
122→    return (
123→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
124→            <button className={styles.backButton} onClick={() => navigate('/home')}>
125→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
126→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
127→                </svg>
128→                Back
129→            </button>
130→
131→            <div className={styles.coordsLabel}>
132→                {centerWorld.x}, {centerWorld.y}
133→            </div>
134→
135→            <Stage
136→                ref={stageRef}
137→                width={stageSize.width}
138→                height={stageSize.height}
139→                {...stageEvents}
140→            >
141→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
142→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
143→                <InteractiveLayer
144→                    layerProps={getLayerProps(1.0)}
145→                    posts={postArray}
146→                    galaxies={galaxies}
147→                    zoom={zoom}
148→                    showTitles={showTitles}
149→                    pulsingId={pulsingId}
150→                    onStarClick={handleStarClick}
151→                    onGalaxyClick={handleGalaxyClick}
152→                />
153→            </Stage>
154→
155→            {selectedGalaxy && galaxyProfile && (
156→                <div className={styles.galaxyPreviewPanel}>
157→                    <button
158→                        className={styles.galaxyPreviewClose}
159→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
160→                    >
161→                        &times;
162→                    </button>
163→                    <div
164→                        className={styles.galaxyPreviewBg}
165→                        style={galaxyProfile.background || {}}
166→                    />
167→                    <div className={styles.galaxyPreviewContent}>
168→                        <img
169→                            className={styles.galaxyPreviewAvatar}
170→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
171→                            alt=""
172→                        />
173→                        <div className={styles.galaxyPreviewHeading}>
174→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
175→                        </div>
176→                        {galaxyProfile.bio && (
177→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
178→                        )}
179→                        <button
180→                            className={styles.galaxyPreviewVisitBtn}
181→                            onClick={() => navigate(`/visit/${selectedGalaxy.userId}`)}
182→                        >
183→                            Visit Profile
184→                        </button>
185→                    </div>
186→                </div>
187→            )}
188→
189→            {selectedPost && (
190→                <div className={styles.previewPanel}>
191→                    <button
192→                        className={styles.previewClose}
193→                        onClick={() => setSelectedPost(null)}
194→                    >
195→                        &times;
196→                    </button>
197→                    <div className={styles.previewAuthor}>
198→                        <img
199→                            className={styles.previewAvatar}
200→                            src={selectedPost.users?.image_url || '/assets/profile.jpg'}
201→                            alt=""
202→                        />
203→                        <span className={styles.previewAuthorName}>
204→                            {selectedPost.users?.name || 'Anonymous'}
205→                        </span>
206→                    </div>
207→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
208→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
209→                    <div className={styles.previewLikes}>
210→                        {Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count
211→                            ? `${selectedPost.likes[0].count} like${selectedPost.likes[0].count !== 1 ? 's' : ''}`
212→                            : '0 likes'}
213→                    </div>
214→                    <button className={styles.previewReadBtn} onClick={handleReadPost}>
215→                        Read
216→                    </button>
217→                </div>
218→            )}
219→        </div>
220→    );
221→};
222→
223→export default Universe;
